<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: linear-gradient(135deg, #eef2ff 0%, #f8fafc 100%);
    color: #1e293b;
    min-height: 100vh;
    padding: 32px 24px;
  }
  h1 {
    margin: 0 0 24px;
    font-size: 28px;
    font-weight: 700;
    letter-spacing: -0.02em;
  }
  .toolbar {
    display: flex;
    gap: 10px;
    margin-bottom: 24px;
    max-width: 980px;
  }
  #new-card {
    flex: 1;
    padding: 12px 14px;
    border: 1px solid #cbd5e1;
    border-radius: 10px;
    font-size: 14px;
    background: #fff;
    transition: border-color .15s, box-shadow .15s;
  }
  #new-card:focus {
    outline: none;
    border-color: #6366f1;
    box-shadow: 0 0 0 3px rgba(99,102,241,.15);
  }
  #add-card {
    padding: 12px 20px;
    border: none;
    border-radius: 10px;
    background: #6366f1;
    color: #fff;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background .15s, transform .05s;
  }
  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: translateY(1px); }

  .board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    max-width: 980px;
  }
  .column {
    background: #ffffff;
    border: 1px solid #e2e8f0;
    border-radius: 14px;
    padding: 16px;
    display: flex;
    flex-direction: column;
    min-height: 320px;
    box-shadow: 0 1px 3px rgba(15,23,42,.04), 0 1px 2px rgba(15,23,42,.06);
    transition: background .15s, border-color .15s;
  }
  .column.drag-over {
    background: #eef2ff;
    border-color: #6366f1;
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 14px;
    padding-bottom: 12px;
    border-bottom: 1px solid #f1f5f9;
  }
  .col-title {
    font-size: 13px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    color: #475569;
  }
  .count {
    background: #e2e8f0;
    color: #475569;
    font-size: 12px;
    font-weight: 700;
    min-width: 22px;
    height: 22px;
    padding: 0 7px;
    border-radius: 11px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }
  .card-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 60px;
  }
  .card {
    background: #fff;
    border: 1px solid #e2e8f0;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    box-shadow: 0 1px 2px rgba(15,23,42,.05);
    cursor: grab;
    transition: box-shadow .15s, transform .05s, border-color .15s;
    word-break: break-word;
  }
  .card:hover {
    box-shadow: 0 4px 12px rgba(15,23,42,.08);
    border-color: #cbd5e1;
  }
  .card:active { cursor: grabbing; }
  .card.dragging {
    opacity: .4;
    transform: rotate(1deg);
  }
  .card-title {
    font-size: 14px;
    line-height: 1.4;
    color: #1e293b;
    flex: 1;
  }
  .card-del {
    background: transparent;
    border: none;
    color: #94a3b8;
    font-size: 18px;
    line-height: 1;
    cursor: pointer;
    padding: 0 2px;
    border-radius: 4px;
    transition: color .15s, background .15s;
    flex-shrink: 0;
  }
  .card-del:hover {
    color: #ef4444;
    background: #fef2f2;
  }
  .empty-hint {
    font-size: 12px;
    color: #94a3b8;
    text-align: center;
    padding: 16px 0;
    font-style: italic;
  }
  @media (max-width: 720px) {
    .board { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
  <h1>Kanban Board</h1>
  <div class="toolbar">
    <input id="new-card" type="text" placeholder="Add a new task..." maxlength="200" />
    <button id="add-card">Add Card</button>
  </div>
  <div class="board">
    <section class="column" id="col-todo">
      <div class="col-header">
        <span class="col-title">To Do</span>
        <span class="count">0</span>
      </div>
      <div class="card-container" data-col="todo"></div>
    </section>
    <section class="column" id="col-doing">
      <div class="col-header">
        <span class="col-title">In Progress</span>
        <span class="count">0</span>
      </div>
      <div class="card-container" data-col="doing"></div>
    </section>
    <section class="column" id="col-done">
      <div class="col-header">
        <span class="col-title">Done</span>
        <span class="count">0</span>
      </div>
      <div class="card-container" data-col="done"></div>
    </section>
  </div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban-board-state-v1";
  var columns = ["todo", "doing", "done"];
  var draggingId = null;

  function uid() {
    return "c_" + Date.now().toString(36) + "_" + Math.random().toString(36).slice(2, 8);
  }

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return { todo: [], doing: [], done: [] };
      var parsed = JSON.parse(raw);
      var state = { todo: [], doing: [], done: [] };
      columns.forEach(function (c) {
        if (Array.isArray(parsed[c])) {
          state[c] = parsed[c].filter(function (card) {
            return card && typeof card.id === "string" && typeof card.title === "string";
          });
        }
      });
      return state;
    } catch (e) {
      return { todo: [], doing: [], done: [] };
    }
  }

  function saveState(state) {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* ignore */ }
  }

  var state = loadState();

  function getContainer(col) {
    var colEl = document.getElementById("col-" + col);
    return colEl.querySelector(".card-container");
  }

  function updateCount(col) {
    var colEl = document.getElementById("col-" + col);
    var countEl = colEl.querySelector(".count");
    countEl.textContent = String(state[col].length);
  }

  function updateAllCounts() {
    columns.forEach(updateCount);
  }

  function createCardElement(card, col) {
    var el = document.createElement("div");
    el.className = "card";
    el.setAttribute("draggable", "true");
    el.setAttribute("data-id", card.id);

    var title = document.createElement("div");
    title.className = "card-title";
    title.textContent = card.title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "×";
    del.addEventListener("click", function (e) {
      e.stopPropagation();
      deleteCard(card.id);
    });

    el.appendChild(title);
    el.appendChild(del);

    el.addEventListener("dragstart", function (e) {
      draggingId = card.id;
      e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", card.id); } catch (err) {}
      el.classList.add("dragging");
    });
    el.addEventListener("dragend", function () {
      el.classList.remove("dragging");
      draggingId = null;
      columns.forEach(function (c) {
        document.getElementById("col-" + c).classList.remove("drag-over");
      });
    });

    return el;
  }

  function findCard(id) {
    for (var i = 0; i < columns.length; i++) {
      var arr = state[columns[i]];
      for (var j = 0; j < arr.length; j++) {
        if (arr[j].id === id) return { col: columns[i], index: j };
      }
    }
    return null;
  }

  function renderColumn(col) {
    var container = getContainer(col);
    container.innerHTML = "";
    if (state[col].length === 0) {
      var hint = document.createElement("div");
      hint.className = "empty-hint";
      hint.textContent = "No cards";
      container.appendChild(hint);
    } else {
      state[col].forEach(function (card) {
        container.appendChild(createCardElement(card, col));
      });
    }
    updateCount(col);
  }

  function renderAll() {
    columns.forEach(renderColumn);
  }

  function addCard(title) {
    var t = (title || "").trim();
    if (!t) return;
    state.todo.push({ id: uid(), title: t });
    saveState(state);
    renderColumn("todo");
  }

  function deleteCard(id) {
    var loc = findCard(id);
    if (!loc) return;
    state[loc.col].splice(loc.index, 1);
    saveState(state);
    renderColumn(loc.col);
  }

  function moveCard(id, targetCol) {
    var loc = findCard(id);
    if (!loc) return;
    if (loc.col === targetCol) return;
    var card = state[loc.col].splice(loc.index, 1)[0];
    state[targetCol].push(card);
    saveState(state);
    renderColumn(loc.col);
    renderColumn(targetCol);
  }

  // Add button + input
  var input = document.getElementById("new-card");
  var addBtn = document.getElementById("add-card");

  function handleAdd() {
    var val = input.value;
    if (!val.trim()) {
      input.value = "";
      return;
    }
    addCard(val);
    input.value = "";
    input.focus();
  }

  addBtn.addEventListener("click", handleAdd);
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") handleAdd();
  });

  // Drag-and-drop on each column
  columns.forEach(function (col) {
    var colEl = document.getElementById("col-" + col);
    colEl.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      colEl.classList.add("drag-over");
    });
    colEl.addEventListener("dragenter", function (e) {
      e.preventDefault();
      colEl.classList.add("drag-over");
    });
    colEl.addEventListener("dragleave", function (e) {
      // Only remove if leaving the column entirely
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove("drag-over");
      }
    });
    colEl.addEventListener("drop", function (e) {
      e.preventDefault();
      colEl.classList.remove("drag-over");
      var id = draggingId;
      if (!id) {
        try { id = e.dataTransfer.getData("text/plain"); } catch (err) {}
      }
      if (id) moveCard(id, col);
    });
  });

  // Initial render
  renderAll();
})();
</script>
</body>
</html>
